const results = $input.first().json.results || [];

let totalImpressions = 0;
let totalClics = 0;
let totalCout = 0;
let totalConversions = 0;

const lignesCampagnes = results.map(r => {
  const m = r.metrics;
  const cout = (m.costMicros / 1_000_000).toFixed(2);
  totalImpressions  += m.impressions;
  totalClics        += m.clicks;
  totalCout         += parseFloat(cout);
  totalConversions  += m.conversions;

  return {
    campagne:     r.campaign.name,
    impressions:  m.impressions,
    clics:        m.clicks,
    cout:         parseFloat(cout),
    conversions:  m.conversions,
    ctr:          (m.ctr * 100).toFixed(2) + '%',
    cpc:          (m.averageCpc / 1_000_000).toFixed(2)
  };
});

const cpa = totalConversions > 0
  ? (totalCout / totalConversions).toFixed(2)
  : 'N/A';

const alerteBudget = totalCout > 40; // adapte selon ton budget journalier

return [{
  json: {
    date: $today.minus({days: 1}).toFormat('dd/MM/yyyy'),
    campagnes: lignesCampagnes,
    totalImpressions,
    totalClics,
    totalCout: totalCout.toFixed(2),
    totalConversions,
    cpa,
    alerteBudget
  }
}];

const d = $input.first().json;

const alerte = d.alerteBudget
  ? '\n⚠️ <b>Budget journalier dépassé 80% — vérifier le rythme de diffusion</b>'
  : '';

const lignes = d.campagnes.map(c =>
  `📌 <b>${c.campagne}</b>\n` +
  `   ${c.clics} clics · ${c.cout}€ · CPC ${c.cpc}€ · ${c.conversions} conv.`
).join('\n\n');

const message =
`💶 <b>Rapport Google Ads — ${d.date}</b>
${alerte}

<b>Résumé global</b>
👁 Impressions  : ${d.totalImpressions}
🖱 Clics        : ${d.totalClics}
💸 Dépense      : ${d.totalCout} €
🎯 Conversions  : ${d.totalConversions}
📉 CPA          : ${d.cpa} €

<b>Détail par campagne</b>
${lignes}`;

return [{ json: { message } }];
